<script lang="ts">
  const html: string = "<h1>AnnouncementBanner</h1>\n\n<p>A persistent, page-level banner for service-wide messages — scheduled maintenance, public-interest news, regulatory notices — that every user should see while the message is active.</p>\n\n<p>The component renders a <code>&lt;div role=\"region\"&gt;</code> so the banner is a labeled landmark in the page outline, named by the required <code>label</code> prop. Two optional behaviours layer on top:</p>\n\n<ul>\n<li><code>dismissible</code> adds a close <code>&lt;button&gt;</code> so users can hide a non-critical banner once they have read it; the consumer decides whether the dismissal is remembered (cookie, local storage, server flag).</li>\n<li><code>live</code> promotes the region to <code>aria-live=\"polite\"</code> so screen readers announce content changes (e.g. updated maintenance ETA) without interrupting the user.</li>\n</ul>\n\n<p>Reach for <code>AnnouncementBanner</code> when the message is broad and persistent. Use <code>Alert</code> for status tied to a specific section or action, <code>Notification</code> / <code>Toast</code> for transient confirmations, and <code>PhaseBanner</code> specifically for alpha/beta service phase messaging.</p>\n\n<h2>Implementation Notes</h2>\n\n<ul>\n<li>Renders a <code>&lt;div role=\"region\"&gt;</code> with an <code>aria-label</code> so screen readers announce the banner as a labeled landmark</li>\n<li>Optional <code>dismissible</code> mode renders a close <code>&lt;button&gt;</code> that hides the banner when activated</li>\n<li>Accepts <code>children</code> slot for the announcement content (text, links, icons composed by the consumer)</li>\n<li>When <code>live</code> is true, the region also gets <code>aria-live=\"polite\"</code> so dynamic content changes are announced</li>\n<li>Spreads <code>restProps</code> onto the root <code>&lt;div&gt;</code> for consumer customization</li>\n</ul>\n\n<h2>Props</h2>\n\n<table>\n<thead>\n<tr><th>Prop</th><th>Type</th><th>Default</th><th>Description</th></tr>\n</thead>\n<tbody>\n<tr><td><code>label</code></td><td>string (required)</td><td>—</td><td>Accessible region label</td></tr>\n<tr><td><code>live</code></td><td>boolean</td><td>false</td><td>Whether the region announces dynamic changes via <code>aria-live=\"polite\"</code></td></tr>\n<tr><td><code>dismissible</code></td><td>boolean</td><td>false</td><td>Whether to render a dismiss button</td></tr>\n<tr><td><code>dismissLabel</code></td><td>string</td><td>\"Dismiss\"</td><td>Accessible label for the dismiss button</td></tr>\n<tr><td><code>onDismiss</code></td><td>callback</td><td>—</td><td>Fired when the user dismisses the banner</td></tr>\n<tr><td><code>children</code></td><td>slot (required)</td><td>—</td><td>Banner content</td></tr>\n<tr><td><code>...restProps</code></td><td>HTML attributes</td><td>—</td><td>Spread onto the root <code>&lt;div&gt;</code></td></tr>\n</tbody>\n</table>\n\n<h2>Usage</h2>\n\n<pre><code class=\"language-html\">&lt;AnnouncementBanner label=\"Service announcement\" dismissible&gt;\n  &lt;p&gt;Maintenance is scheduled for Sunday between 2am and 4am.&lt;/p&gt;\n&lt;/AnnouncementBanner&gt;</code></pre>\n\n<h2>Keyboard Interactions</h2>\n\n<ul>\n<li>Tab moves focus to the dismiss button when present</li>\n<li>Enter or Space activates the dismiss button (native browser behaviour)</li>\n</ul>\n\n<h2>ARIA</h2>\n\n<ul>\n<li><code>role=\"region\"</code> makes the banner a labeled landmark</li>\n<li><code>aria-label</code> (from <code>label</code>) names the region</li>\n<li><code>aria-live=\"polite\"</code> (when <code>live=true</code>) announces content changes without interrupting the user</li>\n<li>Dismiss button has <code>aria-label</code> for the close action</li>\n</ul>\n\n<h2>When to Use</h2>\n\n<ul>\n<li>Communicating service-wide messages such as scheduled maintenance, important news, or new feature launches</li>\n<li>Surfacing time-sensitive information that all users should see</li>\n</ul>\n\n<h2>When Not to Use</h2>\n\n<ul>\n<li>Use <code>Alert</code> for in-flow status messages tied to a specific action or section</li>\n<li>Use <code>Notification</code> for transient toast-style messages</li>\n<li>Use <code>PhaseBanner</code> to indicate the development phase of a service</li>\n<li>Use <code>MedicalBanner</code> for clinical safety information</li>\n</ul>\n\n<h2>Headless</h2>\n\n<p>This headless component renders semantic HTML with appropriate ARIA wiring. The consumer provides all visual styling — no CSS, animations, or layout assumptions are baked in.</p>\n\n<h2>Styles</h2>\n\n<p>The component renders with <code>.announcement-banner</code> as the root class. No default styles are included.</p>\n\n<h2>Related components</h2>\n\n<ul>\n<li><code>banner</code> — generic top-of-page banner</li>\n<li><code>phase-banner</code> — service development phase indicator</li>\n<li><code>alert</code> — in-flow status message</li>\n<li><code>notification</code> — transient toast</li>\n</ul>\n\n<h2>References</h2>\n\n<ul>\n<li><a href=\"https://www.w3.org/TR/wai-aria-1.2/#region\">WAI-ARIA region role</a></li>\n<li><a href=\"https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Attributes/aria-live\">MDN aria-live</a></li>\n</ul>";
  // BEGIN auto-generated component example consts
  const demoHtml: string = "<div class=\"announcement-banner\" aria-label=\"a banner highlighting important messages for all users\">AnnouncementBanner</div>";
  const svelteSource: string = "// In your Svelte component:\nimport AnnouncementBanner from \"lily-design-system-svelte-headless/components/AnnouncementBanner/AnnouncementBanner.svelte\";\n\n<AnnouncementBanner>\n  <!-- content -->\n</AnnouncementBanner>\n";
  // END auto-generated component example consts
</script>

